import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and the processing fee
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("quote a single plain sword → premium 105 G (100 base + 5 fee)");
  it.todo("quote a single plain amulet → premium 65 G (60 base + 5 fee)");
  it.todo("quote a single plain staff → premium 85 G (80 base + 5 fee)");
  it.todo("quote a single plain potion → premium 45 G (40 base + 5 fee)");
  it.todo("quote a sword and an amulet → premium 165 G (100 + 60 + 5 fee)");

  // Components and the block-of-3 rule
  it.todo("quote 1 rune → premium 30 G (25 + 5 fee)");
  it.todo("quote 2 runes → premium 55 G (50 + 5 fee, no block)");
  it.todo("quote 3 runes → premium 65 G (block: 60 + 5 fee)");
  it.todo("quote 4 runes → premium 105 G (100 + 5 fee, no block)");
  it.todo("quote 7 runes → premium 180 G (175 + 5 fee, no block at 7)");
  it.todo("quote 2 runes + 1 moonstone → premium 80 G (75 + 5 fee, no block)");
  it.todo("quote 3 runes + 3 moonstones → premium 125 G (120 + 5 fee, two blocks)");

  // Item-specific modifiers
  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5 fee)");
  it.todo("sword with enchantment 5 → premium 135 G (100 + 30 high enchantment + 5 fee)");
  it.todo("sword with enchantment 4 → no high enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → premium 185 G (100 + 50 + 30 + 5)");

  // Policy-wide modifiers
  it.todo("first insurance: plain sword newcomer → premium 115 G (100 + 10 + 5)");
  it.todo("loyalty discount: plain sword for 2-year customer → premium 85 G (100 - 20 + 5)");
  it.todo("follow-up contract: plain sword on second contract → premium 90 G (100 - 15 + 5)");

  // Multi-item modifier scope
  it.todo("cursed sword + plain amulet for newcomer → premium 231 G (100+60+50 curse +21 first ins +5)");

  // Rounding
  it.todo("premium that yields 197.5 G → final 198 G (rounded up in MHPCO favor)");

  // Integration examples
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer second contract, cursed sword enchantment 7 → premium 160 G");

  // Claim: basic payout
  it.todo("claim with plain sword damage 500 G → payout 400 G, remainingCap 1600 G");
  it.todo("claim with rune damage 200 G → payout 100 G");
  it.todo("claim with high-enchantment sword damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("claim with dragon-material sword damage 1000 G → payout 900 G (full minus deductible)");
  it.todo("claim with dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins)");
  it.todo("claim with dragon-material sword enchantment 8 damage 1000 G → payout 400 G (50% applies)");

  // Multiple damages, deductibles, and cap
  it.todo("claim with two damages (sword 500, amulet 300) → payout 600 G (deductible per item)");
  it.todo("cap exhaustion: two 1500 G claims on a sword → first payout 1400, then 600");

  // Rounding payout
  it.todo("payout that yields 350.5 G → final 350 G (rounded down)");

  // Error cases
  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
  it.todo("claim referencing item not in policy → non-zero exit, error to stderr");
  it.todo("claim with negative damage amount → non-zero exit, error to stderr");
  it.todo("claim with more damages of a type than insured → non-zero exit");
});

