const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: unknown; steps: Step[] };
type QuoteResult = { premium: number };
type StepResult = QuoteResult;

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const totalBasePremium = (items: Item[]): number =>
  items.reduce((total, item) => total + basePremiumForItem(item), 0);

const quote = (step: QuoteStep): QuoteResult => ({
  premium: totalBasePremium(step.items) + PROCESSING_FEE,
});

export const processScenario = (input: Scenario): { results: StepResult[] } => ({
  results: input.steps.map(quote),
});

