  it.todo("claim with high-enchantment sword damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("claim with dragon-material sword damage 1000 G → payout 900 G (full minus deductible)");
  it.todo("claim with dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins)");
  it.todo("claim with dragon-material sword enchantment 8 damage 1000 G → payout 400 G (50% applies)");

  // Multiple damages, deductibles, and cap
  it.todo("claim with two damages (sword 500, amulet 300) → payout 600 G (deductible per item)");
  it.todo("cap exhaustion: two 1500 G claims on a sword → first payout 1400, then 600");

  // Rounding payout
  it.todo("payout that yields 350.5 G → final 350 G (rounded down)");

  // Error cases
  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
  it.todo("claim referencing item not in policy → non-zero exit, error to stderr");
  it.todo("claim with negative damage amount → non-zero exit, error to stderr");
  it.todo("claim with more damages of a type than insured → non-zero exit");
});

