const PROCESSING_FEE = 5;
const COMPONENT_UNIT_PRICE = 25;
const COMPONENT_BLOCK_PRICE = 60;
const COMPONENT_BLOCK_SIZE = 3;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: unknown; steps: Step[] };
type QuoteResult = { premium: number };
type StepResult = QuoteResult;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const partition = <T,>(items: T[], predicate: (item: T) => boolean): [T[], T[]] =>
  items.reduce<[T[], T[]]>(
    ([yes, no], item) => (predicate(item) ? [[...yes, item], no] : [yes, [...no, item]]),
    [[], []],
  );

const countByType = (items: Item[]): Record<string, number> =>
  items.reduce<Record<string, number>>((acc, item) => {
    acc[item.type] = (acc[item.type] ?? 0) + 1;
    return acc;
  }, {});

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * COMPONENT_UNIT_PRICE;

const sumItemBasePremiums = (items: Item[]): number =>
  items.reduce((total, item) => total + basePremiumForItem(item), 0);

const sumComponentPremiums = (components: Item[]): number =>
  Object.values(countByType(components)).reduce(
    (sum, count) => sum + componentGroupPremium(count),
    0,
  );

const totalBasePremium = (items: Item[]): number => {
  const [components, regularItems] = partition(items, isComponent);
  return sumItemBasePremiums(regularItems) + sumComponentPremiums(components);
};

const premiumForItems = (items: Item[]): number =>
  totalBasePremium(items) + PROCESSING_FEE;

const quote = (step: QuoteStep): QuoteResult => ({
  premium: premiumForItems(step.items),
});

export const processScenario = (input: Scenario): { results: StepResult[] } => ({
  results: input.steps.map(quote),
});

